        </section>

        {/* Reviews Section */}
        <section className="space-y-6 pt-6 border-t border-gray-100">
          <div className="flex justify-between items-center">
            <h3 className="text-xl font-bold">Avaliações ({reviews.length})</h3>
          </div>

          <div className="bg-gray-50 p-6 rounded-3xl space-y-4">
            <h4 className="font-bold text-gray-800">Deixe sua avaliação</h4>
            <div className="flex space-x-2">
              {[1, 2, 3, 4, 5].map(star => (
                <button key={star} onClick={() => setUserRating(star)} className="text-2xl">
                  {star <= userRating ? '⭐' : '☆'}
                </button>
              ))}
            </div>
            <textarea
              className="w-full p-4 rounded-2xl border-gray-200 border bg-white focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="Como foi sua experiência?"
              rows={3}
              value={comment}
              onChange={(e) => setComment(e.target.value)}
            />
            <button 
              onClick={() => {
                onSubmitReview(userRating, comment);
                setComment('');
              }}
              className="w-full bg-gray-900 text-white py-3 rounded-xl font-bold hover:bg-black transition-colors"
            >
              Publicar Avaliação
            </button>
          </div>

          <div className="space-y-4">
            {reviews.length === 0 ? (
              <p className="text-gray-400 italic">Ainda não há avaliações. Seja o primeiro!</p>
            ) : (
              reviews.map(review => (
                <div key={review.id} className="border-b border-gray-50 pb-4 last:border-0">
                  <div className="flex justify-between mb-1">
                    <span className="font-bold text-gray-800">{review.userName}</span>
                    <span className="text-xs text-gray-400">{review.date}</span>
                  </div>
                  <div className="flex text-xs text-yellow-400 mb-2">
                    {Array.from({ length: review.rating }).map((_, i) => <span key={i}>★</span>)}
                  </div>
                  <p className="text-gray-600 text-sm">{review.comment}</p>
                </div>
              ))
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

export default BusinessDetails;

import React, { useState } from 'react';
import { User, Business } from '../types';

interface UserFormsProps {
  user: User | null;
  onLogin: (user: User) => void;
  onLogout: () => void;
  onBack: () => void;
  favorites: Business[];
  onSelectBusiness: (id: string) => void;
}

const UserForms: React.FC<UserFormsProps> = ({ user, onLogin, onLogout, onBack, favorites, onSelectBusiness }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', phone: '', password: '' });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Simulate auth
    onLogin({
      id: Date.now().toString(),
      name: form.name || 'Usuário Teste',
      email: form.email,
      phone: form.phone,
      role: 'CONSUMER',
      favorites: []
    });
  };

  if (user) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8 space-y-8">
        <button onClick={onBack} className="text-blue-600 font-medium">← Voltar</button>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 flex items-center space-x-6">
          <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-3xl font-bold">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div className="flex-1">
            <h2 className="text-2xl font-bold">{user.name}</h2>
            <p className="text-gray-500">{user.email}</p>
            <p className="text-gray-500 text-sm">{user.phone}</p>
          </div>
          <button onClick={onLogout} className="bg-red-50 text-red-600 px-4 py-2 rounded-xl font-bold hover:bg-red-100">Sair</button>
        </div>

        <section className="space-y-4">
          <h3 className="text-xl font-bold">Meus Favoritos</h3>
          {favorites.length === 0 ? (
            <p className="text-gray-400">Você ainda não favoritou nenhuma empresa.</p>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {favorites.map(b => (
                <div key={b.id} onClick={() => onSelectBusiness(b.id)} className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center space-x-4 cursor-pointer hover:border-blue-200">
                  <img src={b.imageUrl} className="w-16 h-16 rounded-xl object-cover" />
                  <div>
                    <h4 className="font-bold">{b.name}</h4>
                    <p className="text-xs text-gray-500">{b.category}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto px-4 py-12">
      <div className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100">
        <h2 className="text-2xl font-bold text-center mb-8">{isRegister ? 'Criar Conta' : 'Acessar Conta'}</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          {isRegister && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">Nome Completo</label>
              <input 
                type="text" 
                required 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" 
                value={form.name}
                onChange={e => setForm({...form, name: e.target.value})}
              />
            </div>
          )}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">E-mail</label>
            <input 
              type="email" 
              required 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" 
              value={form.email}
              onChange={e => setForm({...form, email: e.target.value})}
            />
          </div>
          {isRegister && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">Telefone</label>
              <input 
                type="tel" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" 
                value={form.phone}
                onChange={e => setForm({...form, phone: e.target.value})}
              />
            </div>
          )}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">Senha</label>
            <input 
              type="password" 
              required 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" 
              value={form.password}
              onChange={e => setForm({...form, password: e.target.value})}
            />
          </div>
          <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-colors mt-4">
            {isRegister ? 'Cadastrar' : 'Entrar'}
          </button>
        </form>
        <div className="mt-8 text-center text-sm text-gray-500">
          {isRegister ? 'Já possui conta?' : 'Ainda não tem conta?'} 
          <button onClick={() => setIsRegister(!isRegister)} className="ml-1 text-blue-600 font-bold hover:underline">
            {isRegister ? 'Fazer login' : 'Cadastre-se grátis'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default UserForms;

import React from 'react';
import { Business } from '../types';

interface AdminPanelProps {
  businesses: Business[];
  onApprove: (id: string) => void;
  onReject: (id: string) => void;
  onBack: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ businesses, onApprove, onReject, onBack }) => {
  const pending = businesses.filter(b => b.status === 'PENDING');
  const approved = businesses.filter(b => b.status === 'APPROVED');

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 space-y-8">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold">Painel Administrativo</h2>
        <button onClick={onBack} className="text-blue-600 font-medium">Voltar</button>
      </div>

      <section className="space-y-4">
        <h3 className="text-xl font-bold text-orange-600">Aguardando Aprovação ({pending.length})</h3>
        {pending.length === 0 ? (
          <p className="text-gray-400 italic bg-white p-8 rounded-2xl border border-dashed border-gray-200 text-center">Nenhuma pendência no momento.</p>
        ) : (
          <div className="space-y-4">
            {pending.map(b => (
              <div key={b.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                  <h4 className="font-bold text-lg">{b.name}</h4>
                  <p className="text-sm text-gray-500">{b.category} • {b.ownerName}</p>
                  <p className="text-xs text-gray-400 mt-1">{b.address}</p>
                </div>
                <div className="flex space-x-2">
                  <button onClick={() => onApprove(b.id)} className="bg-green-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-green-700 transition-colors">Aprovar</button>
                  <button onClick={() => onReject(b.id)} className="bg-red-50 text-red-600 px-6 py-2 rounded-xl font-bold hover:bg-red-100 transition-colors">Rejeitar</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="space-y-4">
        <h3 className="text-xl font-bold text-gray-800">Empresas Publicadas ({approved.length})</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {approved.map(b => (
            <div key={b.id} className="bg-gray-50 p-4 rounded-xl flex items-center justify-between border border-gray-100">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-gray-200 rounded-lg overflow-hidden">
                  <img src={b.imageUrl} className="w-full h-full object-cover" />
                </div>
                <div>
                  <h4 className="font-bold text-sm">{b.name}</h4>
                  <p className="text-[10px] text-gray-500">{b.category}</p>
                </div>
              </div>
              <button onClick={() => onReject(b.id)} className="text-xs text-red-400 font-bold uppercase tracking-wider">Remover</button>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default AdminPanel;
